SELECT
	HOMEPAGE_ID, FACILITY_IDX, FACILITY_REQ_IDX, APPLY_ID, MEMBER_KEY,
	APPLY_NAME, APPLY_PHONE, APPLY_DESC, APPLY_STATUS, ADD_DATE,
	ADD_ID, MOD_DATE, MOD_ID, SELF_INFO_YN,DESIRED_START_TIME,DESIRED_END_TIME,USER_APLLY_COUNT, BLACKBOARD_USE_YN
FROM
	FACILITY_REQ
WHERE HOMEPAGE_ID = #{homepage_id} 
	AND FACILITY_IDX = #{facility_idx} 
	AND FACILITY_REQ_IDX = #{facility_req_idx}

SELECT COUNT(*) 
FROM FACILITY_REQ
WHERE HOMEPAGE_ID = #{homepage_id} 
	AND FACILITY_IDX = #{facility_idx}
	AND MEMBER_KEY = #{member_key}
	AND DELETE_YN = 'N'
	AND APPLY_STATUS != '3'

mapper.insert:

	SELECT NVL(MAX(FACILITY_REQ_IDX),0)+1 FROM FACILITY_REQ WHERE HOMEPAGE_ID = #{homepage_id} AND FACILITY_IDX = #{facility_idx} 

INSERT INTO FACILITY_REQ
(
	HOMEPAGE_ID, FACILITY_IDX, FACILITY_REQ_IDX, APPLY_ID, MEMBER_KEY, APPLY_NAME, APPLY_PHONE, APPLY_DESC, APPLY_STATUS, SELF_INFO_YN
	, DELETE_YN, ADD_DATE, ADD_ID, BLACKBOARD_USE_YN

		,DESIRED_START_TIME,DESIRED_END_TIME, USER_APLLY_COUNT

) VALUES (
	#{homepage_id}, #{facility_idx}, #{facility_req_idx}, #{apply_id}, #{member_key}, #{apply_name}, #{apply_phone}, #{apply_desc}, '1', #{self_info_yn}
	, 'N', SYSDATE, #{add_id}, #{blackboard_use_yn}

		,#{desired_start_time},#{desired_end_time},#{user_aplly_count}

)

