UPDATE 
	FACILITY_REQ 
SET
	APPLY_PHONE 		= #{apply_phone}
	, APPLY_DESC 		= #{apply_desc}
	, MOD_DATE 			= SYSDATE
	, MOD_ID 			= #{mod_id}
	, BLACKBOARD_USE_YN = #{blackboard_use_yn}
WHERE
	HOMEPAGE_ID = #{homepage_id} 
	AND FACILITY_IDX = #{facility_idx} 
	AND FACILITY_REQ_IDX = #{facility_req_idx} 
	AND DELETE_YN = 'N'

mapper.delete:
UPDATE
	FACILITY_REQ
SET 
	DELETE_YN = 'Y'
	, MOD_DATE = SYSDATE
	, MOD_ID = #{mod_id}
WHERE
	HOMEPAGE_ID = #{homepage_id} 
	AND FACILITY_IDX = #{facility_idx} 
	AND FACILITY_REQ_IDX = #{facility_req_idx}

mapper.update:
UPDATE
	FACILITY_REQ
SET
	APPLY_STATUS = #{apply_status}
	, MOD_DATE = SYSDATE 
	, MOD_ID = #{mod_id}
WHERE
	HOMEPAGE_ID = #{homepage_id} 
	AND FACILITY_IDX = #{facility_idx} 
	AND FACILITY_REQ_IDX = #{facility_req_idx}

	AND MEMBER_KEY = #{member_key}

mapper.select:
SELECT a.FACILITY_NAME, a.USE_DATE, b.APPLY_ID, b.APPLY_NAME, b.APPLY_PHONE, b.APPLY_DESC,b.DESIRED_START_TIME,b.DESIRED_END_TIME,b.USER_APLLY_COUNT, CASE WHEN b.APPLY_STATUS = '1' THEN '신청' WHEN b.APPLY_STATUS = '2' THEN '승인' WHEN b.APPLY_STATUS = '3' THEN '취소' END AS APPLY_STATUS FROM FACILITY_MANAGE a, FACILITY_REQ b WHERE a.HOMEPAGE_ID = b.HOMEPAGE_ID AND a.FACILITY_IDX = b.FACILITY_IDX AND a.HOMEPAGE_ID = #{homepage_id} AND a.DELETE_YN = 'N' AND b.DELETE_YN = 'N' AND substr(a.USE_DATE,0,7) in
EXTRACT(YEAR from sysdate) || '-' || #{i}
ORDER BY a.USE_DATE
